INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 1, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 10001, -470.0, 1, 1.47, 2002, "クローチェ", 2, "2023/09/22 14:59:59", "2023/06/30 12:00:00", 126401);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 1, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 10002, -470.0, 2, 2.15, 2002, "クローチェ", 1, "2023/09/22 14:59:59", "2023/06/30 12:00:00", 126401);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 1, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 10003, -470.0, 1, 0.0, 2002, "ライラエル", 2, "2023/09/22 14:59:59", "2023/06/30 12:00:00", 126501);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 1, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 10004, -470.0, 2, 0.0, 2002, "ライラエル", 1, "2023/09/22 14:59:59", "2023/06/30 12:00:00", 126501);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 2, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 10005, -470.0, 1, 0.0, 2002, "リンド", 2, "2023/12/22 14:59:59", "2023/09/15 15:00:00", 127702);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 2, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 10006, -470.0, 2, 0.0, 2002, "リンド", 2, "2023/12/22 14:59:59", "2023/09/15 15:00:00", 127702);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 2, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 10007, -470.0, 1, 0.0, 2002, "ヴルム", 1, "2023/12/22 14:59:59", "2023/09/15 15:00:00", 127802);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 2, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 10008, -470.0, 2, 6.5, 2002, "ヴルム", 1, "2023/12/22 14:59:59", "2023/09/15 15:00:00", 127802);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 3, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 10009, -470.0, 1, 0.0, 2002, "アネモネ", 1, "2024/03/22 14:59:59", "2023/12/15 15:00:00", 129602);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 3, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 10010, -470.0, 2, 0.0, 2002, "アネモネ", 1, "2024/03/22 14:59:59", "2023/12/15 15:00:00", 129602);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 3, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 10011, -470.0, 1, 0.0, 2002, "ネフィ=ネラ", 1, "2024/03/22 14:59:59", "2023/12/15 15:00:00", 129701);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 3, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 10012, -470.0, 2, 6.2, 2002, "ネフィ=ネラ", 1, "2024/03/22 14:59:59", "2023/12/15 15:00:00", 129701);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 3, 4, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 10013, -470.0, 1, 3.1, 2002, "カノン", 5, "2024/06/22 14:59:59", "2024/03/15 15:00:00", 130301);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 3, 4, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 10014, -470.0, 2, 6.15, 2002, "カノン", 2, "2024/06/22 14:59:59", "2024/03/15 15:00:00", 130301);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 4, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 10015, -470.0, 1, 0.0, 2002, "ナーナ", 2, "2024/06/22 14:59:59", "2024/03/15 15:00:00", 130401);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 4, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 10016, -470.0, 2, 3.35, 2002, "ナーナ", 1, "2024/06/22 14:59:59", "2024/03/15 15:00:00", 130401);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 5, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 10017, -470.0, 1, 0.0, 2002, "ホウオウ", 1, "2024/09/22 14:59:59", "2024/06/15 15:00:00", 130502);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 5, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 10018, -470.0, 2, 3.18, 2002, "ホウオウ", 1, "2024/09/22 14:59:59", "2024/06/15 15:00:00", 130502);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 4, 5, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 10019, -470.0, 3, 0.0, 2002, "ホウオウ", 4, "2024/09/22 14:59:59", "2024/06/15 15:00:00", 130503);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 5, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 10020, -470.0, 1, 4.9, 2002, "ネア", 2, "2024/09/22 14:59:59", "2024/06/15 15:00:00", 123301);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 5, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 10021, -470.0, 2, 4.8, 2002, "ネア", 2, "2024/09/22 14:59:59", "2024/06/15 15:00:00", 123301);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 3, 6, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 10022, -470.0, 1, 4.922, 2002, "カリザ", 1, "2024/12/22 14:59:59", "2024/09/15 15:00:00", 133301);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 3, 6, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 10023, -470.0, 2, 9.638, 2002, "カリザ", 5, "2024/12/22 14:59:59", "2024/09/15 15:00:00", 133301);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 6, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 10024, -470.0, 1, 2.88, 2002, "ミーア", 2, "2024/12/22 14:59:59", "2024/09/15 15:00:00", 133401);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 5, 6, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 10025, -470.0, 2, 4.818, 2002, "ミーア", 1, "2024/12/22 14:59:59", "2024/09/15 15:00:00", 133401);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 7, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 10026, -470.0, 1, 1.78, 2002, "グレイス", 1, "2025/03/22 14:59:59", "2024/12/15 15:00:00", 133002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 7, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 10027, -470.0, 2, 6.15, 2002, "グレイス", 7, "2025/03/22 14:59:59", "2024/12/15 15:00:00", 133002);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 6, 7, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 10028, -470.0, 1, 4.28, 2002, "ヴァイオレット", 2, "2025/03/22 14:59:59", "2024/12/15 15:00:00", 133102);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 7, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 10029, -470.0, 2, 0.0, 2002, "ヴァイオレット", 1, "2025/03/22 14:59:59", "2024/12/15 15:00:00", 133102);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 8, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 10030, -470.0, 1, 5.53, 2002, "ルルィ", 1, "2025/06/23 14:59:59", "2025/03/15 15:00:00", 136902);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 9, 8, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 10031, -470.0, 2, 6.05, 2002, "ルルィ", 7, "2025/06/23 14:59:59", "2025/03/15 15:00:00", 136902);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 8, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 10032, -470.0, 1, 0.0, 2002, "デュラン", 1, "2025/06/23 14:59:59", "2025/03/15 15:00:00", 137001);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 8, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 10033, -470.0, 2, 0.0, 2002, "デュラン", 1, "2025/06/23 14:59:59", "2025/03/15 15:00:00", 137001);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 9, "おう\n好きなもん持ってきな", 10034, -470.0, 1, 0.0, 2002, "サツキ", 2, "2025/09/23 14:59:59", "2025/06/16 15:00:00", 135902);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 9, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 10035, -470.0, 2, 4.935, 2002, "サツキ", 6, "2025/09/23 14:59:59", "2025/06/16 15:00:00", 135902);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 9, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 10036, -470.0, 1, 7.441, 2002, "ユキノ", 5, "2025/09/23 14:59:59", "2025/06/16 15:00:00", 135802);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 7, 9, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 10037, -470.0, 2, 0.0, 2002, "ユキノ", 7, "2025/09/23 14:59:59", "2025/06/16 15:00:00", 135802);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 10, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 10038, -470.0, 1, 2.295, 2002, "クルル", 2, "2025/12/22 14:59:59", "2025/09/16 15:00:00", 130901);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 10, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 10039, -470.0, 2, 6.281, 2002, "クルル", 6, "2025/12/22 14:59:59", "2025/09/16 15:00:00", 130901);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 10, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 10040, -470.0, 1, 5.549, 2002, "ヴォルガーノ", 1, "2025/12/22 14:59:59", "2025/09/16 15:00:00", 137701);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 3, 10, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 10041, -470.0, 2, 2.64, 2002, "ヴォルガーノ", 6, "2025/12/22 14:59:59", "2025/09/16 15:00:00", 137701);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 7, 11, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 10042, -470.0, 1, 7.642, 2002, "ライラエル", 4, "2026/03/23 11:59:59", "2025/12/15 15:00:00", 132801);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 11, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 10043, -470.0, 2, 0.0, 2002, "ライラエル", 1, "2026/03/23 11:59:59", "2025/12/15 15:00:00", 132802);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 11, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 10044, -470.0, 1, 0.0, 2002, "クローチェ", 1, "2026/03/23 11:59:59", "2025/12/15 15:00:00", 134502);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 11, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 10045, -470.0, 2, 3.72, 2002, "クローチェ", 1, "2026/03/23 11:59:59", "2025/12/15 15:00:00", 134501);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 12, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 10046, -470.0, 1, 4.991, 2002, "ネフィ＝ネラ", 1, "2026/06/22 11:59:59", "2026/03/16 12:00:00", 138201);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 12, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 10047, -470.0, 2, 3.877, 2002, "ネフィ＝ネラ", 4, "2026/06/22 11:59:59", "2026/03/16 12:00:00", 138201);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 4, 12, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 10048, -470.0, 1, 1.71, 2002, "アラクネ", 6, "2026/06/22 11:59:59", "2026/03/16 12:00:00", 136001);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 5, 12, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 10049, -470.0, 2, 5.32, 2002, "アラクネ", 2, "2026/06/22 11:59:59", "2026/03/16 12:00:00", 136001);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 9, 13, "水着で、店番とか──\n本当、意味がわかりません\n海の家でもないのに…", 10050, -470.0, 1, 3.727, 2002, "アネモネ", 4, "2026/09/22 11:59:59", "2026/06/15 12:00:00", 135401);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 7, 13, "──リアみたいに、\nもっと愛想良い接客を…\nいえ──なんでもないです", 10051, -470.0, 2, 7.213, 2002, "アネモネ", 9, "2026/09/22 11:59:59", "2026/06/15 12:00:00", 135401);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 1, 13, "いらっしゃいませー♪\n奉仕活動兼、将来のために\nたくさん働いちゃいます♪", 10052, -470.0, 1, 1.874, 2002, "クリア", 2, "2026/09/22 11:59:59", "2026/06/15 12:00:00", 135301);
INSERT INTO `v1_3fe5f48e3cb48cbe980bc81a5f63f173c179c30886b09b84d76445fbf86c7cdd` VALUES (0.0, 2, 13, "アルバイトが終わったら\n海に遊びに行きましょう！\nモネちゃんも一緒に♪", 10053, -470.0, 2, 0.0, 2002, "クリア", 2, "2026/09/22 11:59:59", "2026/06/15 12:00:00", 135301);
